const fs = require('fs');
const path = require('path');

const item = $input.first().json;
const sessionId = item.sessionId;
const chatInput = item.chatInput;

const sessionsDir = '/vault/raw/sessions';
const sessionFile = path.join(sessionsDir, sessionId + '.json');

let session = { notebookInput: '', conversation: [], source: '' };

if (fs.existsSync(sessionFile)) {
  try {
    session = JSON.parse(fs.readFileSync(sessionFile, 'utf8'));
  } catch(e) {
    session = { notebookInput: '', conversation: [], source: '' };
  }
}

const isFirstMessage = session.conversation.length === 0;
if (isFirstMessage) {
  session.notebookInput = chatInput;
  fs.mkdirSync(sessionsDir, { recursive: true });
  fs.writeFileSync(sessionFile, JSON.stringify(session, null, 2), 'utf8');
}

return [{ json: {
  sessionId,
  chatInput,
  notebookInput: session.notebookInput,
  conversation: session.conversation,
  source: session.source || '',
  isFirstMessage
} }];

const item = $input.first().json;
const trimmed = item.chatInput.trim();
const isDone = trimmed.startsWith('完成') || trimmed.toLowerCase().startsWith('done');

let source = item.source || '';
if (!source) {
  const idx = trimmed.indexOf('http');
  if (idx >= 0) source = trimmed.slice(idx).split(' ')[0];
}

return [{ json: { ...item, isDone, source } }];

const item = $input.first().json;
const { chatInput, conversation } = item;

const systemPrompt = `你是一個知識萃取助理。使用者會貼上一段整理好的學習內容。
你的任務是幫助使用者萃取出有價值的問題。

流程：
1. 使用者貼上內容後，先簡短確認你理解了內容（1-2句）
2. 詢問使用者：「你在學習這個主題之前有什麼疑惑，或閱讀過程中冒出什麼問題？」
3. 使用者回答後繼續追問，直到他說沒有更多問題
4. 如果使用者說沒有想法，根據內容主動提出 3-5 個有深度的問題。
   重要：這些問題必須只針對這份內容才有意義，換一篇文章就問不出來的那種。
   好問題範例（針對 CLAUDE.md 文章）：「CLAUDE.md 超過 200 行後怎麼處理比較好？」「Hooks 和 Rules 的界線怎麼判斷？」
   不好的問題範例：「你覺得這個方法有什麼限制？」「這對你有幫助嗎？」
5. 使用者輸入「完成」時結束；若有來源可以一起提供，例如：完成 https://example.com

語氣：簡潔、像組員討論，不要太正式。
語言：全程使用繁體中文，不可使用簡體字。`;

const messages = [
  { role: 'system', content: systemPrompt },
  ...conversation,
  { role: 'user', content: chatInput }
];

return [{ json: { ...item, messages } }];

const fs = require('fs');
const path = require('path');

const prev = $('Build Chat Messages').first().json;
const assistantReply = $input.first().json.choices[0].message.content;

const { sessionId, chatInput, notebookInput, conversation } = prev;
let source = prev.source || '';

if (!source) {
  const idx = chatInput.indexOf('http');
  if (idx >= 0) source = chatInput.slice(idx).split(' ')[0];
}

const updatedConversation = [
  ...conversation,
  { role: 'user', content: chatInput },
  { role: 'assistant', content: assistantReply }
];

const sessionFile = path.join('/vault/raw/sessions', sessionId + '.json');
fs.writeFileSync(sessionFile, JSON.stringify({
  notebookInput,
  conversation: updatedConversation,
  source
}, null, 2), 'utf8');

return [{ json: { output: assistantReply } }];

const item = $input.first().json;
const { sessionId, notebookInput, conversation, source } = item;

if (!conversation || conversation.length < 2) {
  return [{ json: {
    sessionId,
    notebookInput: notebookInput || '',
    conversation: [],
    questionsUser: [],
    questionsModel: [],
    date: new Date().toISOString().split('T')[0],
    authorName: $env.AUTHOR_NAME || 'Unknown',
    modelName: $env.LLM_MODEL || 'Unknown',
    source: source || '',
    isEmpty: true,
    messages: [{ role: 'user', content: 'OUTPUT_EMPTY_SESSION' }]
  }}];
}

const date = new Date().toISOString().split('T')[0];
const authorName = $env.AUTHOR_NAME || 'Unknown';
const modelName = $env.LLM_MODEL || 'Unknown';

const questionsUser = [];
for (let i = 2; i < conversation.length; i++) {
  if (conversation[i].role === 'user') questionsUser.push(conversation[i].content);
}
const questionsModel = [];
for (const m of conversation) {
  if (m.role === 'assistant') {
    const sentences = m.content.split(/(?<=[。？！])/).filter(s => s.includes('？') && s.trim().length > 8);
    questionsModel.push(...sentences);
  }
}

const inputText = conversation[0].content;
const dialogueText = conversation.slice(1)
  .map(m => `${m.role === 'user' ? '使用者' : '助理'}: ${m.content}`)
  .join('\n\n');

const sourceField = source ? source : '';

const prompt = `你的任務是根據以下資料，整理成一份高品質的學習筆記。
全文必須使用繁體中文，對話中若有簡體字一律轉換為繁體中文輸出。

【原始學習內容】
${inputText}

【問題萃取對話】
${dialogueText}

輸出格式（規則：只輸出 markdown 本體，不要加任何說明文字，不要加「請確認」「如需調整」等句子，不要在最後加分隔線或結語）：
---
title: [從內容萃取主題標題，不超過 20 字]
date: ${date}
author: ${authorName}
model: ${modelName}
source: ${sourceField}
tags:
  - [關鍵字1]
  - [關鍵字2]
  - [關鍵字3，以此類推，共 3-5 個繁體中文關鍵字，每個獨立一行]
---

## 摘要
[根據原始學習內容寫 5-8 句。重點是「如何實際操作這些知識」：要有具體步驟、數值、判斷條件。不能只列概念名稱，每句都要有實際資訊量，讓人讀完就知道怎麼做。]

## 問答
[根據「問題萃取對話」中使用者提出的每一個問題，直接從原始學習內容找答案。

格式（每題都要有答案，不能只列問題）：

**Q: [使用者問題原文]**
[具體答案 2-4 句，必須引用原始內容的細節，不能說「可以根據需求調整」這類廢話]
]

## 模型補充問答
[若對話中助理主動提出問題，用相同格式列出並從原始內容回答。若無則完全省略此區塊，連標題都不要寫。]`;

return [{ json: {
  sessionId, notebookInput, conversation,
  questionsUser, questionsModel,
  date, authorName, modelName,
  source: sourceField,
  isEmpty: false,
  messages: [{ role: 'user', content: prompt }]
}}];

const fs = require('fs');
const path = require('path');

const prev = $('Build Summary Prompt').first().json;
const rawContent = $input.first().json.choices[0].message.content;

if (prev.isEmpty || rawContent.includes('OUTPUT_EMPTY_SESSION')) {
  return [{ json: { output: '⚠️ 對話記錄不足，無法整理。\n\n請重新開始：貼入 NotebookLM 內容 → 與模型對話 → 最後輸入「完成」。' }}];
}

const { sessionId, notebookInput, conversation, questionsUser, questionsModel, date, authorName, modelName, source } = prev;

// 強制修正模型可能填錯的 metadata，不論模型寫什麼都以 code 層為準
const markdownContent = rawContent
  .replace(/^date:.*$/m, `date: ${date}`)
  .replace(/^author:.*$/m, `author: ${authorName}`)
  .replace(/^model:.*$/m, `model: ${modelName}`);

const titleMatch = markdownContent.match(/^title:\s*(.+)$/m);
const rawTitle = titleMatch ? titleMatch[1].trim() : `note-${date}`;
const safeTitle = rawTitle.replace(/[\[\]\\/:*?"<>|]/g, '-').replace(/\s+/g, '-');

const yyyymm = date.slice(0, 7);
const mdDir = path.join('/vault/notes', yyyymm);
const rawDir = path.join('/vault/raw', yyyymm);

fs.mkdirSync(mdDir, { recursive: true });
fs.mkdirSync(rawDir, { recursive: true });

const mdPath = path.join(mdDir, safeTitle + '.md');
const rawPath = path.join(rawDir, safeTitle + '.json');

const rawData = {
  date, author: authorName, model: modelName,
  source: source || '',
  input: notebookInput, conversation,
  questions_by_user: questionsUser,
  questions_by_model: questionsModel
};

fs.writeFileSync(mdPath, markdownContent, 'utf8');
fs.writeFileSync(rawPath, JSON.stringify(rawData, null, 2), 'utf8');

const sessionFile = path.join('/vault/raw/sessions', sessionId + '.json');
try { fs.unlinkSync(sessionFile); } catch(e) {}

return [{ json: { output: `筆記已儲存！\n\n📄 ${mdPath}\n📦 ${rawPath}` }}];
